section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/practices-python-ecosystem.json",
  "type": "object",
  "required": [
    "uses_pyproject",
    "src_layout",
    "ruff_configured",
    "mypy_strict",
    "lockfile_present",
    "pre_commit_present"
  ],
  "properties": {
    "uses_pyproject": {
      "type": "boolean",
      "const": true
    },
    "src_layout": {
      "type": "boolean",
      "const": true
    },
    "ruff_configured": {
      "type": "boolean",
      "const": true
    },
    "mypy_strict": {
      "type": "boolean",
      "const": true
    },
    "lockfile_present": {
      "type": "boolean",
      "const": true
    },
    "pre_commit_present": {
      "type": "boolean",
      "const": true
    },
    "no_print_rule": {
      "type": "boolean"
    },
    "py_typed_marker": {
      "type": "boolean"
    },
    "python_min": {
      "type": "string",
      "pattern": "^3\\.(10|11|12|13)$"
    }
  },
  "additionalProperties": false
}
